#include "msconnector/lifecycle_status.h"
const char *msconnector_build_status_name(msconnector_build_status s) { switch (s) { case MSCONNECTOR_BUILD_STATUS_NOT_STARTED: return "not_started"; case MSCONNECTOR_BUILD_STATUS_STARTER: return "starter"; case MSCONNECTOR_BUILD_STATUS_COMPILES: return "compiles"; case MSCONNECTOR_BUILD_STATUS_LINKS: return "links"; case MSCONNECTOR_BUILD_STATUS_RUNTIME_READY: return "runtime_ready"; } return "unknown"; }
const char *msconnector_runtime_status_name(msconnector_runtime_status s) { switch (s) { case MSCONNECTOR_RUNTIME_STATUS_NOT_VERIFIED: return "not_verified"; case MSCONNECTOR_RUNTIME_STATUS_SELF_TEST_ONLY: return "self_test_only"; case MSCONNECTOR_RUNTIME_STATUS_SMOKE_VERIFIED: return "smoke_verified"; case MSCONNECTOR_RUNTIME_STATUS_MATRIX_VERIFIED: return "matrix_verified"; } return "unknown"; }
const char *msconnector_verification_status_name(msconnector_verification_status s) { switch (s) { case MSCONNECTOR_VERIFICATION_STATUS_NONE: return "none"; case MSCONNECTOR_VERIFICATION_STATUS_STATIC_ONLY: return "static_only"; case MSCONNECTOR_VERIFICATION_STATUS_SELF_TEST: return "self_test"; case MSCONNECTOR_VERIFICATION_STATUS_RUNTIME_SMOKE: return "runtime_smoke"; case MSCONNECTOR_VERIFICATION_STATUS_FULL_MATRIX: return "full_matrix"; } return "unknown"; }
